    "001de0df": {"text":"A kinsman rejects the last words and demands the goods. The local court wants something firmer than grief.","hash":"h1-bdc52df8"},
    "003d6d2b": {"text":"Great men forget a child has ears. You learn things worth knowing.","hash":"h1-97625284"},
    "004c5e61": {"text":"Rival","hash":"h1-561c3eeb"},
    "00742549": {"text":"Start seed:","hash":"h1-1fa0f3fa"},
