    "5622b6c7": {"text":"Try the hiring fair.","hash":"h1-dfb7d6de"},
    "56361db9": {"text":"Blood lines run downward — each brood hangs beneath its parents. † marks the dead. Tap a face to open their sheet.","hash":"h1-14519223"},
    "5642c701": {"text":"Raiders took the caravan at a desert well. Your silver is scattered across the sand.","hash":"h1-59b56735"},
    "5660f7f7": {"text":"You wrestle the blade away and pin the assassin, roaring for guards.","hash":"h1-5c224a08"},
    "56619b43": {"text":"⚔ A mercenary company takes your coin — ~150 spears join the host.","hash":"h1-899a6db8"},
    "566e06f9": {"text":"A Suit Against a Neighbor","hash":"h1-1a91545d"},
    "56732add": {"text":"Stewards and secretaries, all day. The great remain unseen.","hash":"h1-d521b94e"},
