    "5d2bea29": {"text":"Highest rank attained","hash":"h1-639e13c5"},
    "5d4dc07d": {"text":"Give alms instead.","hash":"h1-22f5ae17"},
    "5d57bb01": {"text":"Crushed the great rising of the commons.","hash":"h1-c001c139"},
    "5daad4ab": {"text":"Dull","hash":"h1-1d78493e"},
