    "5e37c0e1": {"text":"beginning in {year} AD, aged {age}.","hash":"h1-ef13851d"},
    "5e699f41": {"text":"Debts called in, rumors seeded, friends bought away.","hash":"h1-ab35ec01"},
    "5e71aabb": {"text":"Patrols at every ford and fair. The songs quiet — for now.","hash":"h1-fec1ac3e"},
    "5e79cd81": {"text":"Live quiet, and let men name it.","hash":"h1-f4481121"},
