    "611af7f7": {"text":"Lies starve slower than truth feeds.","hash":"h1-dc36e418"},
    "61230a29": {"text":"Glory or a ditch — the ale decides.","hash":"h1-d4c6f0ca"},
    "61259f5f": {"text":"Defy them to their faces, and pay if it fails.","hash":"h1-5ffe8622"},
