    "d1ee550b": {"text":"A Possible Match","hash":"h1-570474d2"},
    "d1f11fdb": {"text":"Hear their grievances.","hash":"h1-10dc2c00"},
    "d219a691": {"text":"Came home from the war.","hash":"h1-2c74d63f"},
    "d231dc59": {"text":"Bows to no one gladly.","hash":"h1-51319955"},
    "d234e4e5": {"text":"Keep every stalk.","hash":"h1-665e3cca"},
    "d23c8f21": {"text":"Shut your household away.","hash":"h1-e5d28237"},
    "d2489d99": {"text":"Raid them back, twice as hard.","hash":"h1-75a0bd85"},
    "d2837861": {"text":"Masters keep the best work for their own.","hash":"h1-f5abaae0"},
    "d297ea21": {"text":"The granary fed {province} through the famine.","hash":"h1-38abb9cf"},
    "d29c3761": {"text":"Tongues Wag","hash":"h1-412cd1bb"},
    "d2a09ae1": {"text":"📋 Report copied — paste it on Discord, in an email, or a GitHub issue.","hash":"h1-23227fb8"},
    "d2c11e51": {"text":"🏛 Govern the demesne","hash":"h1-b548255b"},
    "d2c50f79": {"text":"Open their sheet and your dealings with them","hash":"h1-1bd4875b"},
    "d2e0ad41": {"text":"🌾 Work your land","hash":"h1-6f4ea9d0"},
    "d2e97ad9": {"text":"The dead deserve better than gulls.","hash":"h1-0abc3f7a"},
    "d2fc9071": {"text":"Patience, whispers, and a long knife. Occupies your focus until sprung.","hash":"h1-e4d56227"},
    "d316d075": {"text":"Heed the counsel.","hash":"h1-690dd4a3"},
    "d361e06f": {"text":"Land of Your Own","hash":"h1-6f4e4df0"},
    "d36ae447": {"text":"Daughter of the lord’s house","hash":"h1-59adfe14"},
    "d36e2097": {"text":"they are not yet of age.","hash":"h1-8bd58b0e"},
    "d371e541": {"text":"The raiders, laden elsewhere, pass the church by. A miracle, plainly.","hash":"h1-c78bd7d9"},
    "d377845b": {"text":"Pull the stakes down after dark.","hash":"h1-51050af8"},
    "d3851101": {"text":"Man-at-Arms","hash":"h1-28351e39"},
    "d38b8397": {"text":"Genius","hash":"h1-ef172d88"},
    "d3914291": {"text":"Your bird stoops first and truest. Bold — perhaps too bold. But men saw it.","hash":"h1-93bad871"},
    "d3c42087": {"text":"Snow seals the doors, and the old ones talk: wars and wonders, debts and dooms, and who really owns the far field.","hash":"h1-6dea040e"},
    "d3dfdced": {"text":"Trust the elders to see straight — if kinship allows.","hash":"h1-00d473a6"},
    "d3e321b1": {"text":"Some chests are best left singing.","hash":"h1-ffa14931"},
    "d3f9ebed": {"text":"The caravan master pays late and short.","hash":"h1-d5882b78"},
    "d4088881": {"text":"💍 Arrange a match…","hash":"h1-aa878b51"},
    "d4151c55": {"text":"One nod, and the house mourns on cue.","hash":"h1-c6b1fdb4"},
    "d4198c27": {"text":"Examine the master’s ledger.","hash":"h1-2a8e81e2"},
    "d45dbab1": {"text":"once your story begins, the ☰ menu holds the full start code to share.","hash":"h1-c288e7fd"},
    "d46d0bbd": {"text":"Cut every thread and swear there never was a web.","hash":"h1-7139d887"},
    "d4752301": {"text":"💰 Seasonal revenue ~{gold} gold · 🛡 levy ~{men} men","hash":"h1-f103ce47"},
    "d4a91419": {"text":"Undermine {name} by fair means or foul.","hash":"h1-35b4ccac"},
