    "d8b86dc9": {"text":"💔 Before witnesses, the marriage to {name} is declared sundered.","hash":"h1-49adea4a"},
    "d8cad03f": {"text":"Good words, empty hands.","hash":"h1-aa1ffe3a"},
    "d8e7d5d1": {"text":"Chaste","hash":"h1-05c57b51"},
    "d8ef7d83": {"text":"A small gift buys a large peace.","hash":"h1-8d612d68"},
