    "d8fbd981": {"text":"mountains","hash":"h1-c5021fe3"},
    "d90d1c41": {"text":"🗣 The house of {name} does not forgive the slight.","hash":"h1-cc891a67"},
    "d915cceb": {"text":"Elected to the town council.","hash":"h1-f3ef3a66"},
    "d91b9101": {"text":"An Omen","hash":"h1-b82e5f89"},
    "d933c039": {"text":"A stranger of real accomplishment in diplomacy.","hash":"h1-800c5cc5"},
    "d9377285": {"text":"The cheapest innovation within reach of your scholarship.","hash":"h1-eadee486"},
