    "db9243c1": {"text":"The world is the last and hardest tutor.","hash":"h1-81d9cb33"},
    "dba83fc1": {"text":"Trust your stars.","hash":"h1-01bb36a9"},
    "dbcc0ce7": {"text":"Your golden lions delight the abbot.","hash":"h1-e435c48c"},
    "dbe23643": {"text":"The watchman is bought, the dogs are fed, and the cart waits in the alder grove. Tonight the lord’s plenty can become yours.","hash":"h1-14478160"},
    "dbeeee6f": {"text":"Flog them and repay the woman.","hash":"h1-f9637ef2"},
    "dbf2d943": {"text":"ArrowRight","hash":"h1-c332bfe0"},
    "dc02f1f3": {"text":"Pursue this match.","hash":"h1-d3b631fe"},
